insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('computer-science:2-2-1-programming-fundamentals:tf:5cea1f12', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tf', 'tf', 1, '{"question": "17 MOD 5 gives the answer 3."}'::jsonb, '{"answer": false, "explain": "17 MOD 5 gives the remainder, which is 2. It is 17 DIV 5 that gives 3."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tf:1591527f', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tf', 'tf', 1, '{"question": "In pseudocode, = is used to assign a value and == is used to compare two values."}'::jsonb, '{"answer": true, "explain": "Correct — = stores a value in a variable; == tests whether two values are equal."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tf:10c2b28b', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tf', 'tf', 1, '{"question": "A count-controlled loop is used when you do not know in advance how many times to repeat."}'::jsonb, '{"answer": false, "explain": "That describes a condition-controlled loop. A count-controlled (for) loop is used when the number of repetitions IS known in advance."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tf:31702067', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tf', 'tf', 1, '{"question": "The AND operator is true only when both of its conditions are true."}'::jsonb, '{"answer": true, "explain": "Correct — AND needs both sides true. OR needs only one side true."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tf:9ffb39b9', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tf', 'tf', 1, '{"question": "Selection means repeating a block of instructions many times."}'::jsonb, '{"answer": false, "explain": "Repeating is iteration. Selection means choosing a path based on whether a condition is true or false."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tf:2b5d939d', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tf', 'tf', 1, '{"question": "A do…until loop always runs its body at least once."}'::jsonb, '{"answer": true, "explain": "Correct — the condition is checked after the body, so the body runs at least once. A while loop can run zero times."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tf:d89709b8', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tf', 'tf', 1, '{"question": "^ is the operator for finding a remainder."}'::jsonb, '{"answer": false, "explain": "^ is the exponent (to the power of) operator. MOD is the operator that finds a remainder."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:c2a9d265', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "What programming is made of", "reading": "<h4>Every program is built from a few basic ideas</h4>\n<ul>\n<li>A <strong>program</strong> is a set of instructions a computer follows. No matter how big, it is built from a small set of fundamentals: <strong>data stored in variables and constants</strong>, <strong>operators</strong> that work on that data, and the <strong>three programming constructs</strong> — <strong>sequence</strong>, <strong>selection</strong> and <strong>iteration</strong>.</li>\n<li>In Paper 2 you read and write algorithms as <strong>pseudocode</strong>, written in OCR''s <strong>Exam Reference Language (ERL)</strong>. It looks a lot like Python, but you are not tied to any one real language.</li>\n<li>This page teaches each fundamental with a short ERL example. Learn to <strong>read</strong> the code (trace it) and <strong>write</strong> it yourself.</li>\n</ul>", "question": "What are the three programming constructs that all programs are built from?", "options": ["Variables, constants and operators, which together store and change all of the data used by the program", "Sequence, selection and iteration", "Input, processing and output, which is the order that a computer always deals with any data in", "Compiling, interpreting and assembling, which are the three ways a program can finally be translated"]}'::jsonb, '{"answer": 1, "explain": "The three constructs are sequence, selection and iteration. Variables/operators and input-process-output are important ideas but not the three constructs."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:32febb1b', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Variables", "reading": "<h4>A named store for a value that can change</h4>\n<ul>\n<li>A <strong>variable</strong> is a named location in memory that holds a value. Its value <strong>can change</strong> while the program runs — that is what \"vary\" means.</li>\n<li>You put a value into a variable using <strong>assignment</strong> (the <code>=</code> sign): the value on the <strong>right</strong> is stored in the name on the <strong>left</strong>.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Pseudocode (ERL)</p><div class=\"code-block\">score = 0\nname = input(\"Enter your name: \")\nscore = score + 10</div></div>\n<div><p class=\"code-label\">Python</p><div class=\"code-block\">score = 0\nname = input(\"Enter your name: \")\nscore = score + 10</div></div>\n</div>\n<ul>\n<li>Think of a variable as a <strong>labelled box</strong>: <code>score</code> is the label, and you can swap what''s inside at any time.</li>\n</ul>", "question": "What is a variable?", "options": ["A fixed value that is written into the program by the programmer and can never be altered while it runs", "A named store in memory whose value can change while the program runs", "A message that the program prints out onto the screen for the user to read while it is running", "A special symbol, such as + or *, that performs a calculation on two different numbers in a program"]}'::jsonb, '{"answer": 1, "explain": "A variable is a named store whose value can change as the program runs — unlike a constant, which stays fixed."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:7eea1242', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Constants", "reading": "<h4>A named value that does NOT change</h4>\n<ul>\n<li>A <strong>constant</strong> is a named value that is set once and <strong>cannot change</strong> while the program runs.</li>\n<li>Use one for a value that is fixed and used in several places — for example a rate of tax, the value of Pi, or a maximum score.</li>\n</ul>\n<div class=\"code-block\">const VAT_RATE = 0.20\nconst MAX_SCORE = 100</div>\n<ul>\n<li><strong>Why use constants?</strong> They make code <strong>easier to read</strong> (a name explains what a number means) and <strong>easier to change</strong> (edit it in <strong>one place</strong> instead of hunting for every <code>0.20</code>). Constant names are often written in CAPITALS.</li>\n</ul>", "question": "Why might a programmer use a constant instead of just typing the number 0.20 throughout their code?", "options": ["Because using a constant somehow makes the whole program run considerably faster than an ordinary plain typed-in number ever could", "Because it gives the value a clear name and can be changed in one place, making the code easier to read and update", "Because a constant is the only way to store a decimal number, as variables can only ever hold whole numbers", "Because constants are automatically kept secret from anyone who might later try to read the program''s code"]}'::jsonb, '{"answer": 1, "explain": "A constant gives the value a meaningful name and means a change is made in one place — improving readability and maintainability."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:c65406d7', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Input, output and assignment", "reading": "<h4>Getting data in, sending results out</h4>\n<ul>\n<li><strong>Input</strong> — read a value from the user with <code>input(...)</code>. It usually comes in as text, so it is often converted to a number (see 2.2.2 casting).</li>\n<li><strong>Output</strong> — display a value with <code>print(...)</code>.</li>\n<li><strong>Assignment</strong> — store a value in a variable with <code>=</code>. It works <strong>right to left</strong>: work out the right-hand side, then put the result in the variable on the left.</li>\n</ul>\n<div class=\"code-block\">age = input(\"How old are you? \")\nnextYear = age + 1\nprint(\"Next year you will be \" + nextYear)</div>\n<ul>\n<li><code>total = total + 1</code> is not a contradiction — it means \"work out the <strong>old</strong> total plus 1, then make that the <strong>new</strong> total\". This is how counters and running totals work.</li>\n</ul>", "question": "What does the statement  count = count + 1  do?", "options": ["It checks whether the variable count is currently equal to count plus one, and reports true or false", "It works out the current value of count plus 1, then stores that new value back into count", "It creates a brand new second variable, also called count, that permanently holds the value 1", "It outputs the value of count to the screen and then adds the number 1 next to it for the user"]}'::jsonb, '{"answer": 1, "explain": "Assignment is right-to-left: the old value of count plus 1 is calculated, then stored back into count. This is how a counter increases."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:ce764044', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Arithmetic operators", "reading": "<h4>Doing maths in a program</h4>\n<ul>\n<li>The usual four: <code>+</code> add, <code>-</code> subtract, <code>*</code> multiply, <code>/</code> divide.</li>\n<li>Plus three you must know for GCSE:</li>\n<li><code>^</code> — <strong>exponent</strong> (to the power of). <code>2 ^ 3</code> = 8.</li>\n<li><code>DIV</code> — <strong>integer (whole-number) division</strong>: the whole number of times one divides into another, throwing away any remainder. <code>17 DIV 5</code> = 3.</li>\n<li><code>MOD</code> — <strong>modulus</strong>: the <strong>remainder</strong> after that division. <code>17 MOD 5</code> = 2.</li>\n</ul>\n<div class=\"code-block\">17 DIV 5   → 3      (5 goes into 17 three whole times)\n17 MOD 5   → 2      (2 is left over)\n2 ^ 3      → 8</div>", "question": "What is the result of  20 DIV 6 ?", "options": ["2, because that is the amount that is left over after taking as many whole sixes as possible out of twenty", "3", "3.33", "6"]}'::jsonb, '{"answer": 1, "explain": "DIV gives the whole number of times 6 divides into 20, which is 3 (the remainder of 2 is discarded). 20 MOD 6 would give the remainder, 2."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:ad700f1e', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "MOD and DIV in action", "reading": "<h4>Why the remainder is so useful</h4>\n<ul>\n<li><strong>Is a number even?</strong> A number is even if it divides by 2 with no remainder — i.e. <code>number MOD 2 == 0</code>.</li>\n<li><strong>Split into groups.</strong> To put 30 students into teams of 4: <code>30 DIV 4</code> = 7 full teams, and <code>30 MOD 4</code> = 2 students left over.</li>\n<li><strong>Get the last digit</strong> of a number: <code>number MOD 10</code>. For 253, <code>253 MOD 10</code> = 3.</li>\n</ul>\n<div class=\"code-block\">if number MOD 2 == 0 then\n  print(\"even\")\nelse\n  print(\"odd\")\nendif</div>", "question": "Which test correctly checks whether the value in  number  is even?", "options": ["number DIV 2 == 0, because DIV finds how many times 2 goes in and an even number always gives zero here", "number MOD 2 == 0", "number MOD 2 == 1, because an even number always leaves a remainder of exactly one when it is halved", "number / 2 == 0, because dividing any even number by two will always give an answer of exactly zero"]}'::jsonb, '{"answer": 1, "explain": "An even number leaves NO remainder when divided by 2, so number MOD 2 == 0. (MOD 2 == 1 tests for odd.)"}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:051e7534', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Comparison operators", "reading": "<h4>Asking true/false questions</h4>\n<ul>\n<li>Comparison operators compare two values and give a <strong>Boolean</strong> result — <strong>true</strong> or <strong>false</strong>. They are what conditions in <code>if</code> and <code>while</code> are built from.</li>\n<li><code>==</code> equal to · <code>!=</code> not equal to · <code>&lt;</code> less than · <code>&lt;=</code> less than or equal to · <code>&gt;</code> greater than · <code>&gt;=</code> greater than or equal to.</li>\n</ul>\n<div class=\"code-block\">5 &gt; 3      → true\n5 == 3     → false\n5 != 3     → true\n7 &lt;= 7     → true</div>\n<ul>\n<li><strong>Watch the trap:</strong> <code>=</code> means <strong>assign</strong> (store a value); <code>==</code> means <strong>compare</strong> (are these equal?). Using <code>=</code> where you meant <code>==</code> is one of the most common mistakes.</li>\n</ul>", "question": "What is the difference between  =  and  ==  ?", "options": ["There is no real difference between them; they both simply check whether two values are equal to each other", "= assigns a value to a variable, whereas == compares two values and gives a true or false result", "= compares two values for equality, whereas == is used to store a new value inside a variable", "= is used only with numbers and == is used only with text, but otherwise they do exactly the same job"]}'::jsonb, '{"answer": 1, "explain": "= stores a value in a variable (assignment); == tests whether two values are equal (comparison). Mixing them up is a classic error."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:94f2a997', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Boolean operators (AND, OR, NOT)", "reading": "<h4>Combining conditions</h4>\n<ul>\n<li><strong>Boolean operators</strong> join or invert conditions:</li>\n<li><code>AND</code> — true only if <strong>both</strong> sides are true.</li>\n<li><code>OR</code> — true if <strong>either</strong> side (or both) is true.</li>\n<li><code>NOT</code> — <strong>reverses</strong> a condition: <code>NOT true</code> is false.</li>\n</ul>\n<div class=\"code-block\">if age &gt;= 13 AND age &lt;= 19 then\n  print(\"You are a teenager\")\nendif\n\nif day == \"Sat\" OR day == \"Sun\" then\n  print(\"It''s the weekend\")\nendif</div>\n<ul>\n<li>These let one condition test more than one thing at once — e.g. a value being <strong>within a range</strong> uses <code>AND</code>.</li>\n</ul>", "question": "A condition is written as  score &gt;= 40 AND score &lt;= 69 . When is it true?", "options": ["When score is 40 or more, OR 69 or less, which as it happens is true for absolutely every possible score", "Only when score is both 40 or more AND 69 or less — that is, anywhere from 40 to 69 inclusive", "Only when score is exactly equal to either the number 40 or the number 69, but no other value in between", "Whenever score is either less than 40 or greater than 69, i.e. any score that sits outside that range"]}'::jsonb, '{"answer": 1, "explain": "AND needs BOTH sides true, so score must be ≥40 and ≤69 — the range 40 to 69 inclusive."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:f3c35c08', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Sequence", "reading": "<h4>One step after another, in order</h4>\n<ul>\n<li><strong>Sequence</strong> is the simplest construct: instructions are carried out <strong>one after another, top to bottom, in the order they are written</strong>.</li>\n<li>Order matters — swapping two lines can change the result.</li>\n</ul>\n<div class=\"code-block\">length = 5\nwidth = 3\narea = length * width\nprint(area)</div>\n<ul>\n<li>Here each line depends on the ones before it: you can''t work out <code>area</code> until <code>length</code> and <code>width</code> exist.</li>\n</ul>", "question": "What does ''sequence'' mean as a programming construct?", "options": ["The program repeats a set of instructions over and over again until some particular condition finally becomes true", "Instructions are carried out one after another, in the order they are written", "The program chooses between two or more different paths depending on whether a condition is true or false", "The instructions are automatically sorted into alphabetical order by the computer before the program is run"]}'::jsonb, '{"answer": 1, "explain": "Sequence means running instructions in order, top to bottom. Repeating is iteration; choosing a path is selection."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:2545502d', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Selection (if / else)", "reading": "<h4>Choosing a path based on a condition</h4>\n<ul>\n<li><strong>Selection</strong> lets a program <strong>choose</strong> what to do, based on whether a condition is true or false. It uses <code>if … then … else … endif</code>, and <code>elseif</code> for extra branches.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Pseudocode (ERL)</p><div class=\"code-block\">if mark &gt;= 70 then\n  print(\"Distinction\")\nelseif mark &gt;= 40 then\n  print(\"Pass\")\nelse\n  print(\"Fail\")\nendif</div></div>\n<div><p class=\"code-label\">Python</p><div class=\"code-block\">if mark &gt;= 70:\n  print(\"Distinction\")\nelif mark &gt;= 40:\n  print(\"Pass\")\nelse:\n  print(\"Fail\")</div></div>\n</div>\n<ul>\n<li>Only <strong>one</strong> branch runs — the first whose condition is true. (OCR also allows a <code>switch/case</code> for choosing between many fixed values.)</li>\n</ul>", "question": "In the grade example above, what is printed when mark is 55?", "options": ["Both \"Pass\" and \"Fail\" are printed, because 55 is not high enough to reach the Distinction branch at the top", "Pass", "Fail", "Distinction, because once a mark is 40 or more the program treats it as reaching the highest grade band"]}'::jsonb, '{"answer": 1, "explain": "55 is not ≥70, but it is ≥40, so the elseif branch runs and prints \"Pass\". Only the first matching branch runs."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:c5ad18fb', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Iteration — count-controlled (for)", "reading": "<h4>Repeat a set number of times</h4>\n<ul>\n<li><strong>Iteration</strong> means repeating instructions (a <strong>loop</strong>). A <strong>count-controlled</strong> loop repeats a <strong>known, fixed number of times</strong>, using a <strong>for</strong> loop with a counter.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Pseudocode (ERL)</p><div class=\"code-block\">for i = 1 to 5\n  print(i)\nnext i</div></div>\n<div><p class=\"code-label\">Python</p><div class=\"code-block\">for i in range(1, 6):\n  print(i)</div></div>\n</div>\n<ul>\n<li>The counter <code>i</code> starts at 1, goes up by one each time, and the loop stops after 5 — printing 1, 2, 3, 4, 5.</li>\n<li>Use a count-controlled loop when you <strong>know in advance how many times</strong> to repeat.</li>\n</ul>", "question": "When is a count-controlled (for) loop the right choice?", "options": ["When you do not know in advance how many times to repeat, and must keep going until a condition changes", "When you know in advance exactly how many times the loop should repeat", "When you only ever want the instructions inside the loop to run one single time and then stop completely", "When you need the program to choose between two different paths rather than repeating anything at all"]}'::jsonb, '{"answer": 1, "explain": "A count-controlled (for) loop is used when the number of repetitions is known in advance. Not knowing means a condition-controlled loop."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:80b8c8ba', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Iteration — condition-controlled (while / do-until)", "reading": "<h4>Repeat until a condition changes</h4>\n<ul>\n<li>A <strong>condition-controlled</strong> loop repeats <strong>while (or until) a condition</strong> is met — used when you <strong>don''t know in advance</strong> how many repetitions are needed.</li>\n<li><code>while … endwhile</code> checks the condition <strong>before</strong> each pass, so it may run <strong>zero</strong> times.</li>\n<li><code>do … until</code> checks the condition <strong>after</strong> each pass, so it always runs <strong>at least once</strong>.</li>\n</ul>\n<div class=\"code-block\">password = input(\"Password: \")\nwhile password != \"secret\"\n  password = input(\"Wrong. Try again: \")\nendwhile\nprint(\"Access granted\")</div>\n<ul>\n<li>Here the loop keeps asking until the right password is typed — you can''t know how many tries that will take.</li>\n</ul>", "question": "What is the key difference between a  while  loop and a  do … until  loop?", "options": ["A while loop can only ever repeat a fixed, pre-set number of times, whereas a do…until loop is the only kind of loop that is able to repeat any number of times at all", "A while loop checks its condition before each pass (so it may run zero times); do…until checks after, so it always runs at least once", "A while loop is used for numbers and a do…until loop is used for text, but otherwise they behave in exactly the same way", "A while loop chooses between two paths, whereas a do…until loop simply runs its instructions once in strict order"]}'::jsonb, '{"answer": 1, "explain": "A while loop tests the condition first (may run zero times); do…until tests after the body, so it always runs at least once."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:learn:9dbeeed1', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'learn', 'mcq', 1, '{"readingTitle": "Count-controlled vs condition-controlled", "reading": "<h4>Choosing the right loop</h4>\n<ul>\n<li>The exam often asks you to pick, or justify, the right kind of loop:</li>\n<li><strong>Count-controlled (for)</strong> — you know the number of repetitions <strong>in advance</strong> (e.g. \"do this 10 times\", \"for each of the 5 scores\").</li>\n<li><strong>Condition-controlled (while / do-until)</strong> — you <strong>don''t</strong> know the number in advance; you repeat <strong>until something happens</strong> (e.g. \"until the user enters 0\", \"while there is still input\").</li>\n</ul>\n<div class=\"code-block\">// known count → for loop\nfor i = 1 to 10\n  ...\nnext i\n\n// unknown count → while loop\nwhile guess != answer\n  ...\nendwhile</div>", "question": "A program keeps asking the user for a number until they type a value between 1 and 10. Which loop suits this best?", "options": ["A count-controlled for loop, because the program will always end up needing to run for exactly ten separate repetitions in total, no matter what the user does", "A condition-controlled loop (while or do…until), because you cannot know in advance how many tries the user will take", "A sequence with no loop at all, because asking the user for a value only ever needs to happen a single time", "A selection statement on its own, because the program simply chooses whether the entered number is valid or not"]}'::jsonb, '{"answer": 1, "explain": "You don''t know how many attempts the user will need, so a condition-controlled loop (repeat until valid) is right — not a fixed for loop."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:misc:5a4194a9', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Using = when you mean == (or thinking they are the same).</p><p><strong>✅ The correct idea:</strong> <strong>=</strong> is <strong>assignment</strong> — it <em>stores</em> the right-hand value into a variable. <strong>==</strong> is <strong>comparison</strong> — it <em>asks</em> whether two values are equal and gives true/false. A condition (in an <code>if</code> or <code>while</code>) needs <code>==</code>.</p>", "question": "Which symbol belongs in a condition that tests whether  score  equals 100?", "options": ["=, because a single equals sign is the standard way to check that two values are the same as each other", "==, because a condition compares two values and == is the comparison operator for ''is equal to''", "MOD, because you need to find the remainder before you are able to compare the score against one hundred", "!=, because that is the operator that specifically checks whether the score has reached exactly one hundred"]}'::jsonb, '{"answer": 1, "explain": "A condition compares values, so it needs == (equal to). A single = would try to assign, not compare."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:misc:d3494c34', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mixing up MOD and DIV.</p><p><strong>✅ The correct idea:</strong> <strong>DIV</strong> gives the <strong>whole-number result</strong> of a division (how many times it goes in); <strong>MOD</strong> gives the <strong>remainder</strong> left over. For 17 and 5: <code>17 DIV 5 = 3</code> and <code>17 MOD 5 = 2</code>. A memory hook: <strong>D</strong>IV = the <strong>D</strong>ivision result; MOD = what''s left over.</p>", "question": "What is  17 DIV 5 ?", "options": ["2, which is the amount that is left over once five has been divided into seventeen as many times as it can be", "3", "3.4", "5"]}'::jsonb, '{"answer": 1, "explain": "DIV gives the whole-number result: 5 goes into 17 three times, so 17 DIV 5 = 3. The remainder (2) is 17 MOD 5."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:misc:bfd6ab43', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a variable and a constant are the same thing.</p><p><strong>✅ The correct idea:</strong> Both are <strong>named stores</strong>, but a <strong>variable''s</strong> value <strong>can change</strong> as the program runs, while a <strong>constant''s</strong> value is <strong>fixed</strong> once set. Use a constant for values that should never change, like a tax rate.</p>", "question": "Which of these should be stored as a CONSTANT rather than a variable?", "options": ["A running total of a player''s score, which needs to go up and down repeatedly as they play through the game", "The fixed rate of VAT (0.20) that is used in several places and should never change while the program runs", "The user''s latest guess in a guessing game, which is different every single time they are asked to enter one", "The current number of items in a shopping basket, which changes each time the user adds or removes something"]}'::jsonb, '{"answer": 1, "explain": "A fixed value used in several places (the VAT rate) suits a constant. The others all change as the program runs, so they are variables."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:misc:a2dc0912', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Confusing count-controlled and condition-controlled loops.</p><p><strong>✅ The correct idea:</strong> A <strong>count-controlled</strong> (for) loop runs a <strong>known number of times</strong>. A <strong>condition-controlled</strong> (while / do-until) loop runs <strong>until a condition changes</strong>, when you <strong>don''t know</strong> the number in advance. Ask: ''Do I know how many times?'' Yes → for; No → while.</p>", "question": "A loop must keep running until the user finally types the word ''quit''. Which type of loop is this?", "options": ["A count-controlled loop, because the program can always work out the exact number of repetitions before it starts", "A condition-controlled loop, because you cannot know in advance how many times the user will type before quitting", "Neither — this task cannot be done with a loop at all, and must instead be written out as a plain sequence", "A selection statement, because the program only has to decide once whether the user has typed the word quit"]}'::jsonb, '{"answer": 1, "explain": "The number of repetitions is unknown (it depends on the user), so it''s condition-controlled — repeat until they type ''quit''."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:misc:ab253b26', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Reading assignment  x = x + 1  as an impossible equation.</p><p><strong>✅ The correct idea:</strong> It is <strong>not</strong> an equation to solve — assignment works <strong>right to left</strong>. The computer works out the <strong>right-hand side using the old value</strong> of <code>x</code>, then stores the result as the <strong>new</strong> <code>x</code>. So if x was 4, <code>x = x + 1</code> makes x become 5.</p>", "question": "If  total  currently holds 7, what does  total = total + 3  leave in  total ?", "options": ["It leaves nothing valid, because a variable can never be defined in terms of itself within a single statement", "10, because the old value 7 is added to 3 and the result is stored back into total as its new value", "3, because the number on the right of the equals sign simply replaces whatever total used to be holding", "It leaves 7 unchanged, because the two sides of the statement have to be equal for it to be allowed to run"]}'::jsonb, '{"answer": 1, "explain": "The right-hand side (7 + 3) is worked out first, then stored back into total, giving 10."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:misc:08e7e335', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a while loop always runs at least once.</p><p><strong>✅ The correct idea:</strong> A <strong>while</strong> loop checks its condition <strong>before</strong> the first pass, so if the condition is already false it runs <strong>zero</strong> times. It is the <strong>do…until</strong> loop that always runs at least once, because it checks <strong>after</strong> the body.</p>", "question": "A while loop''s condition is false before the loop is even reached. How many times does its body run?", "options": ["Once, because every loop is guaranteed to run its body a minimum of one single time before any checking happens", "Zero times, because a while loop checks the condition before each pass and the condition is already false", "Exactly the number set by its counter, because a while loop always repeats a fixed number of times overall", "It runs forever, because a false condition means the loop can never find a reason to stop itself running"]}'::jsonb, '{"answer": 1, "explain": "A while loop tests first, so a condition that is already false means the body runs zero times."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tips:97085468', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tips', 'mcq', 1, '{"readingTitle": "tip — How to trace code line by line", "reading": "<p>\"What does this output?\" and trace-table questions are worth a lot on Paper 2, and you get them right by being <strong>slow and mechanical</strong>, not by reading the code and guessing.</p>\n<ul>\n<li>Draw a small table with a <strong>column for each variable</strong> (and one for output).</li>\n<li>Work through <strong>one line at a time</strong>, writing the new value each time a variable changes. Never skip a loop pass.</li>\n<li>For a loop, check the <strong>condition</strong> each pass and stop the moment it is false.</li>\n</ul>\n<p><strong>Example:</strong> for <code>total = 0</code> then <code>for i = 1 to 3 … total = total + i … next i</code>, your table fills in i = 1 (total 1), i = 2 (total 3), i = 3 (total 6). Output: 6. Slow beats clever.</p>", "question": "What is the safest way to answer a ''what does this code output?'' question?", "options": ["Read the whole program quickly and write down the answer that looks the most likely based on the variable names", "Build a trace table and work through one line at a time, writing each variable''s new value as it changes", "Run the code in your head as fast as you can so you do not run out of time for the other questions on the paper", "Count the number of lines of code in the program, since that is usually equal to the value it will output"]}'::jsonb, '{"answer": 1, "explain": "Tracing line by line in a table, updating each variable as it changes, is the reliable method — guessing from names is not."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tips:12f18b71', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tips', 'mcq', 1, '{"readingTitle": "explain — MOD and DIV: show the working", "reading": "<p>You''ll be asked to work out <code>MOD</code> and <code>DIV</code> results, and to use them (e.g. testing for even, splitting into groups). Do it in two steps:</p>\n<ul>\n<li>First find the <strong>whole number of times</strong> the divisor goes in — that''s the <strong>DIV</strong> answer.</li>\n<li>Then find what''s <strong>left over</strong> — that''s the <strong>MOD</strong> answer.</li>\n</ul>\n<p><strong>Worked:</strong> <code>30 DIV 7</code> → 7 goes into 30 four times (28), so <strong>DIV = 4</strong>; 30 − 28 = 2 left over, so <code>30 MOD 7</code> <strong>= 2</strong>. And remember the classic use: <code>n MOD 2 == 0</code> tests whether <code>n</code> is even.</p>", "question": "Using the two-step method, what are  30 DIV 7  and  30 MOD 7 ?", "options": ["DIV is 2 and MOD is 4, because 30 MOD 7 counts how many whole times seven divides into thirty altogether", "DIV is 4 and MOD is 2, because 7 goes into 30 four times (28) with 2 left over", "DIV is 4.3 and MOD is 0, because seven divides into thirty exactly with only a small decimal part remaining", "DIV is 7 and MOD is 30, because DIV always gives the divisor and MOD always gives the original number back"]}'::jsonb, '{"answer": 1, "explain": "7 into 30 is 4 whole times (28), so DIV = 4; 30 − 28 = 2 left over, so MOD = 2."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tips:211b4fec', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tips', 'mcq', 1, '{"readingTitle": "tip — Naming the constructs and choosing the right loop", "reading": "<p>Questions frequently ask you to <strong>name</strong> the three constructs, or to <strong>choose and justify</strong> a loop. Keep the definitions crisp:</p>\n<ul>\n<li><strong>Sequence</strong> — steps in order. <strong>Selection</strong> — choose a path (<code>if</code>). <strong>Iteration</strong> — repeat (loop).</li>\n<li><strong>for</strong> loop → when you <strong>know</strong> the number of repeats. <strong>while / do-until</strong> → when you <strong>don''t</strong> (repeat until a condition changes).</li>\n</ul>\n<p>If a question says \"repeat until the user enters a valid value\" or \"keep going while there is more data\", that''s a <strong>condition-controlled</strong> loop — the count isn''t known ahead of time. \"Do this for each of the 5 items\" is <strong>count-controlled</strong>.</p>", "question": "A question asks you to justify using a while loop rather than a for loop for validating user input. What is the best justification?", "options": ["A while loop is always faster than a for loop, so it should be chosen whenever a program needs to run quickly", "You cannot know in advance how many times the user will enter invalid data, so the number of repeats is unknown", "A for loop cannot contain an if statement inside it, whereas a while loop is able to make decisions as it repeats", "A while loop uses less memory than a for loop because it does not need to store a counter variable anywhere at all"]}'::jsonb, '{"answer": 1, "explain": "Validation repeats an unknown number of times (until the input is valid), so a condition-controlled while loop fits — not a fixed for loop."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:fib:510f73e3', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'fib', 'fib', 1, '{"question": "A _____ is a named store in memory whose value can change while the program runs.", "blankOptions": {"B1": ["variable", "AND", "MOD", "DIV"]}}'::jsonb, '{"blanks": {"B1": "variable"}}'::jsonb),
