('computer-science:2-2-1-programming-fundamentals:match:2156c9a4', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Assignment ( = )”?", "options": ["Gives the remainder after a whole-number division", "Comparison — is true when two values are equal", "Boolean — true only when both conditions are true", "Stores the value on the right into the variable on the left"]}'::jsonb, '{"answer": 3, "explain": "“Assignment ( = )” means: Stores the value on the right into the variable on the left"}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:match:afeeff1c', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “MOD”?", "options": ["A named value that is fixed and cannot change while the program runs", "Gives the remainder after a whole-number division", "A named store whose value can change while the program runs", "Comparison — is true when two values are equal"]}'::jsonb, '{"answer": 1, "explain": "“MOD” means: Gives the remainder after a whole-number division"}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:match:2ad4f0ac', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “DIV”?", "options": ["A named value that is fixed and cannot change while the program runs", "Gives the whole number of times one value divides into another", "Exponent — raises a number to a power", "Boolean — true only when both conditions are true"]}'::jsonb, '{"answer": 1, "explain": "“DIV” means: Gives the whole number of times one value divides into another"}'::jsonb),
