('computer-science:2-2-2-data-types:mcq:896e5d1e', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "A program stores a single letter grade such as ''A''. Which data type is most suitable?", "options": ["String, because a string is the data type that is used for holding any letters of the alphabet at all", "Character", "Integer", "Real"]}'::jsonb, '{"answer": 1, "explain": "A single letter, digit or symbol is stored as a character. A string is used for a sequence of more than one character."}'::jsonb),
('computer-science:2-2-2-data-types:mcq:9041d011', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "What is the purpose of casting in a program?", "options": ["Rounding a real number to the nearest whole number so it can be displayed more neatly on screen", "Converting a value from one data type to another", "Comparing two values to see whether they are equal to each other", "Joining two or more separate strings together into one longer string"]}'::jsonb, '{"answer": 1, "explain": "Casting converts a value from one data type to another, e.g. from a string to an integer."}'::jsonb),
('computer-science:2-2-2-data-types:mcq:077707aa', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "In pseudocode/Python, input() always returns a value of which data type?", "options": ["Integer, because any value the user types on the keyboard is treated as a whole number automatically", "String", "Boolean", "Real"]}'::jsonb, '{"answer": 1, "explain": "input() always returns a string, even if the user types digits — it must be cast before being used in maths."}'::jsonb),
('computer-science:2-2-2-data-types:mcq:235095cf', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "Which function is used to convert a value into a whole number?", "options": ["str()", "int()", "bool()", "float()"]}'::jsonb, '{"answer": 1, "explain": "int() casts a value to an integer. str() converts to string, bool() to Boolean, float() to real."}'::jsonb),
('computer-science:2-2-2-data-types:mcq:eca31617', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "What does int(7.9) evaluate to?", "options": ["8, because int() rounds a real number up or down to the nearest whole number automatically", "7", "7.9", "0"]}'::jsonb, '{"answer": 1, "explain": "int() drops (truncates) the decimal part rather than rounding, so int(7.9) gives 7, not 8."}'::jsonb),
('computer-science:2-2-2-data-types:mcq:eb58eb58', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "Which function converts a number into a string, so it can be joined onto other text with +?", "options": ["int()", "str()", "float()", "bool()"]}'::jsonb, '{"answer": 1, "explain": "str() converts a value to a string. Joining a number directly onto text with + causes an error unless it is first cast."}'::jsonb),
('computer-science:2-2-2-data-types:mcq:4bac4ef1', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "A program stores whether a customer is a member (yes or no). Which data type is most suitable?", "options": ["String, because storing the actual words ''yes'' and ''no'' is the clearest way of recording this fact", "Boolean", "Character", "Integer"]}'::jsonb, '{"answer": 1, "explain": "A yes/no fact is best stored as a Boolean (true/false) — it can be used directly in a condition, unlike a string."}'::jsonb),
('computer-science:2-2-2-data-types:mcq:6577a47f', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "A shop''s prices are stored as integers instead of real numbers. What is the most likely consequence?", "options": ["No consequence, because an integer can store exactly the same range and precision as a real number", "Pence are lost — a price like £4.99 can only be stored as 4, losing the .99", "The program will refuse to run, since prices must always be stored as strings", "Prices will automatically be rounded to the nearest ten pounds"]}'::jsonb, '{"answer": 1, "explain": "Storing money as an integer discards the decimal part, so £4.99 loses its pennies — this causes inaccurate totals."}'::jsonb),
('computer-science:2-2-2-data-types:mcq:fa0510ef', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "Which data type would be most suitable for storing a customer''s full name?", "options": ["Character, because a name is usually short and character is the type reserved for short pieces of text", "String", "Integer", "Boolean"]}'::jsonb, '{"answer": 1, "explain": "A name is a sequence of characters of varying length, so it needs a string. Character holds only a single symbol."}'::jsonb),
('computer-science:2-2-2-data-types:mcq:a792ee63', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'mcq', 'mcq', 1, '{"question": "Which of the following is a real (float) value?", "options": ["12", "12.5", "true", "''A''"]}'::jsonb, '{"answer": 1, "explain": "12.5 has a decimal part, so it is a real (float) value. 12 is an integer, true is Boolean, and ''A'' is a character."}'::jsonb),
('computer-science:2-2-2-data-types:tf:c98915a5', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tf', 'tf', 1, '{"question": "An integer can store a number with a decimal part, such as 3.5."}'::jsonb, '{"answer": false, "explain": "An integer stores whole numbers only. A number with a decimal part needs a real (float) data type."}'::jsonb),
('computer-science:2-2-2-data-types:tf:450b438a', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tf', 'tf', 1, '{"question": "A Boolean value can only ever be true or false."}'::jsonb, '{"answer": true, "explain": "Correct — Boolean is limited to exactly two values, true and false."}'::jsonb),
('computer-science:2-2-2-data-types:tf:b135d602', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tf', 'tf', 1, '{"question": "A character can store more than one letter, such as ''Hi''."}'::jsonb, '{"answer": false, "explain": "A character holds exactly one letter, digit or symbol. A sequence of letters like ''Hi'' needs a string."}'::jsonb),
('computer-science:2-2-2-data-types:tf:baa7fa6a', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tf', 'tf', 1, '{"question": "input() always returns a value as a string, even if the user types a number."}'::jsonb, '{"answer": true, "explain": "Correct — input() always returns a string, which is why it often needs to be cast before use in maths."}'::jsonb),
('computer-science:2-2-2-data-types:tf:8141efab', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tf', 'tf', 1, '{"question": "int(7.8) rounds the value to give 8."}'::jsonb, '{"answer": false, "explain": "int() does not round — it truncates (drops the decimal part), so int(7.8) gives 7, not 8."}'::jsonb),
('computer-science:2-2-2-data-types:tf:20b8ffc7', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tf', 'tf', 1, '{"question": "str() is used to convert a number into a string so it can be joined onto text with +."}'::jsonb, '{"answer": true, "explain": "Correct — a number must be cast to a string with str() before it can be joined onto text with +."}'::jsonb),
('computer-science:2-2-2-data-types:tf:d8449946', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tf', 'tf', 1, '{"question": "Storing a price such as £4.99 as an integer keeps the value fully accurate."}'::jsonb, '{"answer": false, "explain": "An integer cannot store the decimal part, so £4.99 loses its pennies and becomes inaccurate."}'::jsonb),
('computer-science:2-2-2-data-types:tf:3d2db9a8', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tf', 'tf', 1, '{"question": "Choosing a suitable data type for each piece of data helps keep a program''s values accurate and easy to use correctly."}'::jsonb, '{"answer": true, "explain": "Correct — the right data type avoids lost accuracy (like price as integer) and avoids needing extra casting."}'::jsonb),
('computer-science:2-2-2-data-types:learn:75ce8b41', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "The five data types", "reading": "<h4>Every value in a program has a data type</h4>\n<ul>\n<li>A <strong>data type</strong> tells the computer what <strong>kind</strong> of value is being stored, and what can be done with it. The OCR specification names <strong>five</strong> data types you must know.</li>\n<li><strong>Integer</strong> — a whole number, with no decimal part (e.g. <code>17</code>, <code>-4</code>).</li>\n<li><strong>Real</strong> (also called <strong>float</strong>) — a number that has a decimal part (e.g. <code>3.14</code>, <code>0.5</code>).</li>\n<li><strong>Boolean</strong> — one of only two values: <code>true</code> or <code>false</code>.</li>\n<li><strong>Character</strong> — a <strong>single</strong> letter, digit or symbol (e.g. <code>''A''</code>, <code>''7''</code>, <code>''!''</code>).</li>\n<li><strong>String</strong> — a <strong>sequence</strong> of characters, i.e. text of any length (e.g. <code>\"Hello\"</code>, <code>\"GCSE\"</code>).</li>\n</ul>", "question": "Which data type stores one whole number, such as 42, with no decimal part?", "options": ["Real, because a real number is simply any ordinary number that a program is able to store and work with", "Integer", "Boolean", "Character"]}'::jsonb, '{"answer": 1, "explain": "Integer stores a whole number with no decimal part. Real (float) is for numbers that DO have a decimal part."}'::jsonb),
('computer-science:2-2-2-data-types:learn:662e7afb', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "Integer", "reading": "<h4>Whole numbers, positive or negative</h4>\n<ul>\n<li>An <strong>integer</strong> stores a <strong>whole number</strong> — it never has a decimal part.</li>\n<li>Use it for things that are naturally counted in whole units: someone''s <strong>age in complete years</strong>, a <strong>score</strong>, the <strong>number of items</strong>, a <strong>year</strong>.</li>\n</ul>\n<div class=\"code-block\">age = 15\nlives = 3\nyear = 2026</div>\n<ul>\n<li>An integer can be negative (e.g. a temperature of <code>-4</code>), but it can never store a fractional value like <code>15.5</code>.</li>\n</ul>", "question": "Which of these is most suitable for storing as an integer?", "options": ["The average height of a class of students in metres, worked out to two decimal places such as 1.63", "The number of students in a class", "The exact amount of rainfall recorded in millimetres, such as 12.7", "A single character representing a student''s exam grade, such as ''B''"]}'::jsonb, '{"answer": 1, "explain": "The number of students is always a whole number, so it suits an integer. Height and rainfall need decimal places (real), and a grade letter is a character."}'::jsonb),
('computer-science:2-2-2-data-types:learn:8814585a', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "Real (float)", "reading": "<h4>Numbers with a decimal part</h4>\n<ul>\n<li>A <strong>real</strong> number (also called a <strong>float</strong>) can store a value <strong>with a decimal part</strong>.</li>\n<li>Use it whenever a value could reasonably need decimal places: a <strong>height</strong>, a <strong>weight</strong>, an <strong>average</strong>, a <strong>price</strong>.</li>\n</ul>\n<div class=\"code-block\">height = 1.72\naverage = 68.5\nprice = 4.99</div>\n<ul>\n<li>Even if a real value happens to be a whole number right now (e.g. an average of <code>70.0</code>), it should still be stored as real if it might need decimal places later.</li>\n</ul>", "question": "Which of these values is a real (float) value?", "options": ["7, because seven is a perfectly ordinary number and every ordinary number counts as a real value", "3.5", "true", "''X''"]}'::jsonb, '{"answer": 1, "explain": "3.5 has a decimal part, so it is a real (float) value. 7 alone is a whole number (integer); true is Boolean; ''X'' is a character."}'::jsonb),
('computer-science:2-2-2-data-types:learn:2593af9b', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "Boolean", "reading": "<h4>Only ever true or false</h4>\n<ul>\n<li>A <strong>Boolean</strong> stores exactly <strong>one of two values</strong>: <code>true</code> or <code>false</code>. Nothing else can be stored in it.</li>\n<li>Use it for a <strong>yes/no</strong> or <strong>on/off</strong> fact: is the player still alive, is a customer a member, has the form been filled in.</li>\n</ul>\n<div class=\"code-block\">isMember = true\ngameOver = false\nisRaining = false</div>\n<ul>\n<li>A comparison such as <code>score &gt; 50</code> also produces a Boolean result (true or false) — that is why Boolean values are what conditions in <code>if</code> and <code>while</code> are built from.</li>\n</ul>", "question": "Which data type is most suitable for storing whether a light switch is currently on?", "options": ["String, because the words ''on'' and ''off'' are pieces of text and text always has to be stored as a string", "Boolean", "Character", "Integer"]}'::jsonb, '{"answer": 1, "explain": "A switch has exactly two states, so it suits a Boolean (true/false) — not a string, which would need to be compared as text."}'::jsonb),
('computer-science:2-2-2-data-types:learn:029092d4', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "Character", "reading": "<h4>Exactly one letter, digit or symbol</h4>\n<ul>\n<li>A <strong>character</strong> stores <strong>a single</strong> letter, digit or symbol — never more than one.</li>\n<li>Use it for a value that can <strong>never be more than one symbol</strong>: an <strong>initial</strong>, a <strong>grade letter</strong>, a single key the user has pressed.</li>\n</ul>\n<div class=\"code-block\">initial = ''M''\ngrade = ''B''\nkey = ''!''</div>\n<ul>\n<li>Character is <strong>not</strong> the same as a short string. <code>''A''</code> is a character; <code>\"AB\"</code> or even <code>\"A\"</code> written with double quotes as text of any length is a string.</li>\n</ul>", "question": "A program stores a single letter representing a student''s exam grade (e.g. ''B''). Which data type is most suitable?", "options": ["String, because a string is able to hold letters and a single letter is nothing more than very short text", "Character", "Integer", "Boolean"]}'::jsonb, '{"answer": 1, "explain": "A value that is always exactly one letter, digit or symbol is a character. A string would suit text that could be more than one character."}'::jsonb),
('computer-science:2-2-2-data-types:learn:21e0b291', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "String", "reading": "<h4>A sequence of characters — text of any length</h4>\n<ul>\n<li>A <strong>string</strong> stores a <strong>sequence of characters</strong> — that is, text made up of any number of characters, including none at all (an <strong>empty string</strong>, <code>\"\"</code>).</li>\n<li>Use it for <strong>names</strong>, <strong>addresses</strong>, <strong>sentences</strong> — any text that could be more than one character.</li>\n</ul>\n<div class=\"code-block\">name = \"Priya Kaur\"\naddress = \"12 Elm Road\"\nmessage = \"Well done!\"</div>\n<ul>\n<li>Strings are written in <strong>quote marks</strong> in code. Even a string of digits, such as <code>\"2026\"</code>, is text — it cannot be used in a calculation until it is cast to a number.</li>\n</ul>", "question": "Which data type is most suitable for storing a customer''s full postal address?", "options": ["Character, because character is the data type used for any piece of text that a program needs to store", "String", "Real", "Boolean"]}'::jsonb, '{"answer": 1, "explain": "An address is a sequence of characters of varying length, so it needs a string. Character can only hold a single symbol."}'::jsonb),
('computer-science:2-2-2-data-types:learn:90ed408a', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "Why casting is needed", "reading": "<h4>Converting a value from one data type to another</h4>\n<ul>\n<li><strong>Casting</strong> means converting a value from one data type to another.</li>\n<li>The most common reason it is needed: the function <code>input(...)</code> <strong>always returns a string</strong>, even if the user types digits. To do maths with that value, it must first be cast to a number.</li>\n</ul>\n<div class=\"code-block\">age = input(\"How old are you? \")   // age is the STRING \"15\", not the number 15\nnextYear = age + 1                 // ERROR — a string cannot be added to a number</div>\n<ul>\n<li>Casting is also needed when <strong>joining a number onto text</strong> with <code>+</code> — the number must first be cast to a string, or the same error occurs.</li>\n</ul>", "question": "Why does the line  nextYear = age + 1  cause an error if age was set using input()?", "options": ["It does not cause an error, because input() always returns a whole number that is ready to be used in a calculation", "input() returns age as a string, and a string cannot be added directly to an integer without casting", "The variable age has not been given a name yet, so the computer has nowhere to store the result of the sum", "The + symbol can only be used with Boolean values, never with numbers of any kind at all"]}'::jsonb, '{"answer": 1, "explain": "input() always returns a string, so age holds text, not a number. It must be cast (e.g. with int()) before 1 can be added to it."}'::jsonb),
('computer-science:2-2-2-data-types:learn:7f7cf818', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "The casting functions", "reading": "<h4>str(), int(), float() and bool()</h4>\n<ul>\n<li><code>str(x)</code> — casts <code>x</code> to a <strong>string</strong>. Needed before joining a number onto text with <code>+</code>.</li>\n<li><code>int(x)</code> — casts <code>x</code> to an <strong>integer</strong>. If <code>x</code> has a decimal part, it is <strong>dropped</strong> (not rounded).</li>\n<li><code>float(x)</code> (sometimes written <code>real(x)</code>) — casts <code>x</code> to a <strong>real</strong> number.</li>\n<li><code>bool(x)</code> — casts <code>x</code> to a <strong>Boolean</strong>.</li>\n</ul>\n<div class=\"code-block\">age = int(input(\"Enter your age: \"))\nprint(\"Next year you will be \" + str(age + 1))</div>\n<ul>\n<li>Here <code>input()</code> gives a string, <code>int(...)</code> converts it to a whole number so <code>+ 1</code> works, and <code>str(...)</code> converts the result back to a string so it can be joined onto the message.</li>\n</ul>", "question": "What does int(8.9) evaluate to?", "options": ["9, because int() rounds a real number up or down to whichever whole number is closest to it", "8", "8.9", "0"]}'::jsonb, '{"answer": 1, "explain": "int() drops (truncates) the decimal part rather than rounding, so int(8.9) gives 8, not 9."}'::jsonb),
('computer-science:2-2-2-data-types:learn:f25a2b9b', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "Casting: reading the code", "reading": "<h4>Tracing a value''s type through a program</h4>\n<ul>\n<li>Exam questions often show a short program and ask what it outputs, or why a line causes an error. Track the <strong>data type</strong> of each variable as you read, not just its value.</li>\n</ul>\n<div class=\"code-block\">price = input(\"Enter the price: \")   // price is a STRING, e.g. \"4.99\"\nprice = float(price)                // price is now a REAL, 4.99\ntotal = price * 3                   // total is a REAL, 14.97\nprint(\"Total: £\" + str(total))      // total is cast to a STRING to join it on</div>\n<ul>\n<li>If the <code>float(price)</code> line was missing, <code>price * 3</code> would try to multiply a string by a number — which fails, because <code>price</code> is still text.</li>\n</ul>", "question": "In the example above, what would happen if the line  price = float(price)  was removed?", "options": ["Nothing would change — price would still work perfectly in the calculation on the line below it", "The line total = price * 3 would fail, because price would still be a string, not a number", "The program would automatically cast price to a real number anyway, without needing that line", "The final print statement would no longer work, even though the calculation above it would be fine"]}'::jsonb, '{"answer": 1, "explain": "Without the cast, price stays a string, so price * 3 fails — a string cannot be used in a numeric calculation."}'::jsonb),
('computer-science:2-2-2-data-types:learn:dafee953', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "Choosing a suitable data type", "reading": "<h4>Match the data to the type</h4>\n<ul>\n<li>To choose a data type, ask: <strong>what kind of value is it, and what will be done with it?</strong></li>\n<li><strong>Age</strong> (whole years, used in maths) → <strong>integer</strong>.</li>\n<li><strong>Price</strong> (needs pence) → <strong>real</strong>.</li>\n<li><strong>\"Is a member?\"</strong> (yes/no) → <strong>Boolean</strong>.</li>\n<li><strong>Initial</strong> (always one letter) → <strong>character</strong>.</li>\n<li><strong>Name</strong> (text of any length) → <strong>string</strong>.</li>\n</ul>\n<p>When justifying a choice, always <strong>name the type</strong> and give the <strong>reason it fits this exact data</strong> — not just a general definition of the type.</p>", "question": "A program stores the number of pets a student owns. Which data type is most suitable, and why?", "options": ["Real, because a decimal point makes any number look more precise and therefore more accurate to work with", "Integer, because the number of pets is always a whole number", "String, because numbers can always be stored as text just as easily as they can be stored as numbers", "Boolean, because owning pets is something that is either completely true or completely false for a student"]}'::jsonb, '{"answer": 1, "explain": "The number of pets is counted in whole units, so integer is the suitable type — real and string add nothing needed here."}'::jsonb),
('computer-science:2-2-2-data-types:learn:eb53e12d', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'learn', 'mcq', 1, '{"readingTitle": "Consequences of a poor choice", "reading": "<h4>Picking the wrong type causes real problems</h4>\n<ul>\n<li><strong>Price stored as an integer</strong> — the pennies are lost. <code>£4.99</code> can only be stored as <code>4</code>, so totals become inaccurate.</li>\n<li><strong>Age stored as a string</strong> — it cannot be used directly in a calculation without casting first, and nothing stops invalid text such as <code>\"twelve\"</code> being stored.</li>\n<li><strong>Yes/no fact stored as a string</strong> (e.g. <code>\"yes\"</code>) — it cannot be combined with <code>AND</code>/<code>OR</code>/<code>NOT</code> like a real Boolean can, and has to be compared as exact text instead.</li>\n</ul>\n<p>The exam may ask you to <strong>identify the problem</strong> caused by a poor choice, or to <strong>suggest a better type</strong> and explain the improvement.</p>", "question": "A shop stores each item''s price as an integer instead of a real number. What is the most likely consequence?", "options": ["No consequence, because an integer can store exactly the same values as a real number can", "Amounts with pence, such as £3.49, cannot be stored accurately — the pennies are lost", "The program will crash immediately every single time a price is entered by the user", "Prices will be automatically converted into a string so that they can be displayed on screen"]}'::jsonb, '{"answer": 1, "explain": "An integer cannot hold a decimal part, so a price like £3.49 loses its pennies — this causes inaccurate totals."}'::jsonb),
('computer-science:2-2-2-data-types:misc:6ff7f483', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking int() rounds a decimal number to the nearest whole number.</p><p><strong>✅ The correct idea:</strong> <strong>int()</strong> does not round — it <strong>truncates</strong> (drops) the decimal part, always cutting towards zero. So <code>int(7.9)</code> gives <strong>7</strong>, not 8, and <code>int(-7.9)</code> gives <strong>-7</strong>, not -8.</p>", "question": "What does int(4.7) give?", "options": ["5, because int() always rounds a decimal number up or down to the nearest whole number", "4", "4.7", "0"]}'::jsonb, '{"answer": 1, "explain": "int() truncates (drops) the decimal part rather than rounding, so int(4.7) gives 4."}'::jsonb),
('computer-science:2-2-2-data-types:misc:fd0fb664', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a character and a string of one letter are exactly the same thing.</p><p><strong>✅ The correct idea:</strong> A <strong>character</strong> can hold only <strong>one</strong> single letter, digit or symbol. A <strong>string</strong> is a <strong>sequence</strong> of characters — it can hold one character, many characters, or even none at all. Choose character only when the data can never be more than a single symbol (e.g. a grade letter).</p>", "question": "Which statement correctly describes the difference between character and string?", "options": ["There is no real difference between them at all; both data types are always limited to holding exactly one single letter or symbol", "Character holds exactly one symbol; string holds a sequence of any number of characters, including none", "Character is used only for storing numbers, and string is used only for storing letters of the alphabet", "String can only ever hold a single symbol, while character can hold any amount of text"]}'::jsonb, '{"answer": 1, "explain": "Character is limited to a single symbol; string can hold any length of text, including an empty string."}'::jsonb),
('computer-science:2-2-2-data-types:misc:5b11bd8f', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Forgetting that input() always returns a string, even when the user types digits.</p><p><strong>✅ The correct idea:</strong> Whatever the user types into <code>input(...)</code> is stored as a <strong>string</strong> — typing 15 gives the string <code>\"15\"</code>, not the integer 15. To use it in maths it must first be <strong>cast</strong> with <code>int()</code> or <code>float()</code>.</p>", "question": "A student types 20 in response to  input(\"Enter a number: \") . What is stored, before any casting takes place?", "options": ["The integer 20, ready to be used straight away in any calculation the program needs to do", "The string \"20\"", "The real number 20.0, because input() always adds a decimal point automatically", "Nothing is stored, because input() cannot accept numbers typed by the user at all"]}'::jsonb, '{"answer": 1, "explain": "input() always returns a string, so \"20\" is stored as text, not as the number 20, until it is cast."}'::jsonb),
('computer-science:2-2-2-data-types:misc:a31eded5', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing a data type choice makes no real difference as long as the value ''looks right'' when printed.</p><p><strong>✅ The correct idea:</strong> A poor choice can quietly cause errors or lost accuracy — e.g. storing a <strong>price</strong> as an <strong>integer</strong> loses the pennies, and storing an <strong>age</strong> as a <strong>string</strong> means it cannot be used directly in a calculation without casting first.</p>", "question": "Why does storing a price as an integer rather than a real cause a problem, even if it looks fine on screen at first?", "options": ["It does not cause any problem, since the digits displayed on screen will always still look correct", "It loses the pence, e.g. £4.99 can only be stored as 4, so totals built from it become inaccurate", "The program will refuse to display the price on screen at all if it is stored as an integer", "An integer automatically converts itself into a string the moment it is printed to the screen"]}'::jsonb, '{"answer": 1, "explain": "An integer cannot hold a decimal part, so a price such as £4.99 loses its pence — this makes totals inaccurate."}'::jsonb),
('computer-science:2-2-2-data-types:misc:3a6d2465', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking + always adds numbers together, even when the values are strings.</p><p><strong>✅ The correct idea:</strong> When both values are <strong>strings</strong>, <code>+</code> <strong>joins them together</strong> rather than adding numbers. Mixing a string and a number with <code>+</code> (e.g. <code>\"Score: \" + 10</code>) causes an error unless the number is first cast to a string with <code>str()</code>.</p>", "question": "What does \"Score: \" + str(10) produce?", "options": ["An error, because a string and a number can never be joined together no matter how it is written", "The string \"Score: 10\"", "The number 10, with the text \"Score: \" simply thrown away and ignored", "The Boolean value true, because + is used to compare two values for equality"]}'::jsonb, '{"answer": 1, "explain": "str(10) casts 10 to the string \"10\" first, so + can join it onto \"Score: \", giving \"Score: 10\"."}'::jsonb),
('computer-science:2-2-2-data-types:misc:5619d4a9', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking Boolean values must be typed as the words ''true'' and ''false'' in quotes, like a string.</p><p><strong>✅ The correct idea:</strong> A real <strong>Boolean</strong> value is not text — it is not written in quote marks. <code>true</code> is a Boolean; <code>\"true\"</code> is a <strong>string</strong> that merely contains the letters t-r-u-e, and behaves completely differently in a condition.</p>", "question": "What data type is  \"true\"  (written with quote marks), as opposed to  true  (written without)?", "options": ["It is still a Boolean value, because the word true always means the same thing no matter how it is written", "A string — quote marks always create a string, even if the text inside looks like a Boolean value", "An integer, because quote marks are used in programming to represent the number 1", "A character, because \"true\" is exactly four letters long and characters can be up to four letters"]}'::jsonb, '{"answer": 1, "explain": "Quote marks create a string. \"true\" is text containing the letters t-r-u-e — it is not the Boolean value true."}'::jsonb),
('computer-science:2-2-2-data-types:tips:4234de9e', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tips', 'mcq', 1, '{"readingTitle": "tip — Choosing a data type: ask two questions", "reading": "<p>\"Choose a suitable data type\" and \"justify your choice\" questions come up often. Answer them by asking two questions about the data:</p>\n<ul>\n<li><strong>What kind of value is it?</strong> A whole number → integer. A number that could need decimal places → real. A yes/no fact → Boolean. Always exactly one symbol → character. Any other text → string.</li>\n<li><strong>What will be done with it?</strong> If it needs to be used in a calculation, it must not be a string. If it is compared with AND/OR/NOT, it should be a Boolean, not text like \"yes\".</li>\n</ul>\n<p>When justifying, name the <strong>type</strong> and give the <strong>reason specific to this data</strong> — \"integer, because the number of items is always a whole number\" scores; \"integer, because integers are a data type\" does not.</p>", "question": "A question asks you to justify storing a student''s age as an integer. Which answer is best?", "options": ["Integer, because integer is one of the five data types listed in the specification", "Integer, because age in complete years is always a whole number", "Integer, because integers can be used in any program for any kind of data at all", "Integer, because it is the first data type that most programmers usually think of"]}'::jsonb, '{"answer": 1, "explain": "A good justification links the TYPE to a reason specific to THIS data — age in whole years is naturally a whole number."}'::jsonb),
('computer-science:2-2-2-data-types:tips:79b3b318', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tips', 'mcq', 1, '{"readingTitle": "explain — Casting: match the function to the target type", "reading": "<p>Questions may show a line of code with a cast missing, or ask you to trace a program''s data types line by line. Keep the four functions straight:</p>\n<ul>\n<li><code>int(x)</code> → integer (decimal part <strong>dropped</strong>, not rounded).</li>\n<li><code>float(x)</code> → real (decimal part kept).</li>\n<li><code>str(x)</code> → string (needed before joining a number onto text with +).</li>\n<li><code>bool(x)</code> → Boolean.</li>\n</ul>\n<p><strong>Worked trace:</strong> <code>n = input(\"Enter a number: \")</code> makes <code>n</code> a string. <code>n = int(n)</code> makes it an integer. <code>print(\"Value: \" + str(n))</code> then casts it back to a string so it can join onto the text — without that last cast, the line would fail.</p>", "question": "In the worked trace above, why is str(n) needed in the final print line?", "options": ["It is not actually needed at all — the line would carry on working in exactly the same way whether it was included or left out", "Because n is an integer by that point, and a number cannot be joined onto text with + without being cast to a string first", "Because print() is only able to display values that have already been stored using the string data type in the first place", "Because str() is required every single time any variable of any kind is used anywhere at all inside a print statement"]}'::jsonb, '{"answer": 1, "explain": "By that point n has been cast to an integer, so it must be cast to a string with str() before + can join it onto text."}'::jsonb),
('computer-science:2-2-2-data-types:tips:d6cbe505', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'tips', 'mcq', 1, '{"readingTitle": "tip — Spotting the consequence of a poor data type choice", "reading": "<p>\"Explain the problem caused by storing X as Y\" questions want a <strong>specific</strong> consequence, not just \"it is wrong\". Common patterns:</p>\n<ul>\n<li><strong>Money as integer</strong> → pence are lost, so totals become inaccurate.</li>\n<li><strong>Number as string</strong> → cannot be used in a calculation without casting, and invalid values (like \"twelve\") are not prevented.</li>\n<li><strong>Yes/no fact as string</strong> → cannot be combined with AND/OR/NOT the way a real Boolean can, and must be compared as exact text.</li>\n</ul>\n<p>Always link your answer back to <strong>what the program actually needs to do</strong> with the value.</p>", "question": "A program stores whether a customer has paid as the string \"yes\" or \"no\", instead of a Boolean. What is a valid consequence to give in an exam answer?", "options": ["There is no real consequence at all, because the strings \"yes\" and \"no\" behave in exactly the same way as the Boolean values true and false", "It cannot be combined directly with AND/OR/NOT like a Boolean, and must instead be compared as exact text", "The program will not be able to store the value \"no\" at all, only ever the value \"yes\"", "Storing it as a string will make the whole program run considerably faster than storing it as a Boolean"]}'::jsonb, '{"answer": 1, "explain": "A string like \"yes\" cannot be used directly in a Boolean condition the way true/false can — it needs an exact text comparison."}'::jsonb),
('computer-science:2-2-2-data-types:fib:8e7ffe90', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'fib', 'fib', 1, '{"question": "A(n) _____ data type stores a whole number, such as 17 or -4.", "blankOptions": {"B1": ["casting", "real", "character", "integer"]}}'::jsonb, '{"blanks": {"B1": "integer"}}'::jsonb),
