('computer-science:2-2-2-data-types:fib:623c188f', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'fib', 'fib', 1, '{"question": "The input() function always returns a value of type _____.", "blankOptions": {"B1": ["int()", "string", "real", "sequence"]}}'::jsonb, '{"blanks": {"B1": "string"}}'::jsonb),
('computer-science:2-2-2-data-types:match:043e375b', 'computer-science', 'computer-science:2-2-2-data-types', '2.2.2 Data Types', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Integer”?", "options": ["One of only two values — true or false", "Can lose accuracy, e.g. storing a price as an integer loses the pennies", "A whole number, with no decimal part", "A number with a decimal part"]}'::jsonb, '{"answer": 2, "explain": "“Integer” means: A whole number, with no decimal part"}'::jsonb)
